mapper.update:
UPDATE esg.tb_safety_inspection_log 
SET check_start = #{checkStart},
    check_end = #{checkEnd},
    setup_location = #{setupLocation},
    non_compliance_action = #{nonComplianceAction},
    updated_at = NOW(),
    updated_by = #{updatedBy}
WHERE write_year = #{writeYear}
  AND doc_type = #{docType}
  AND doc_no = #{docNo}
  AND comp_id = #{compId}

	    UPDATE esg.tb_safety_inspection_log_detail 
	       SET acceptable_yn = #{checkList.acceptableYn},
	           non_compliant_yn = #{checkList.nonCompliantYn},
	           updated_at = NOW(),
               updated_by = #{hseInspectionsDetailSaveVO.updatedBy}
         WHERE write_year = #{hseInspectionsDetailSaveVO.writeYear}
           AND doc_type = #{hseInspectionsDetailSaveVO.docType}
           AND doc_no = #{hseInspectionsDetailSaveVO.docNo}
           AND doc_seq = #{checkList.docSeq}

UPDATE esg.tb_safety_inspection_log 
SET use_yn = 'N',
    updated_at = NOW(),
    updated_by = #{updatedBy}
WHERE write_year = #{writeYear}
  AND doc_type = #{docType}
  AND doc_no = #{docNo}
  AND comp_id = #{compId}
